package main

import (
	"bufio"
	"fmt"
	"net"
	"strings"
)

type Client struct {
	conn     net.Conn
	username string
	role     string
}

var clients = make(map[net.Conn]*Client)

func main() {
	listener, err := net.Listen("tcp", ":8080")
	if err != nil {
		fmt.Println("Error listening:", err)
		return
	}
	defer listener.Close()

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println("Error accepting: ", err)
			return
		}

		go handleConnection(conn)
	}
}

func handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)
	username, _ := reader.ReadString('\n')
	role, _ := reader.ReadString('\n')
	clients[conn] = &Client{conn: conn, username: strings.TrimSpace(username), role: strings.TrimSpace(role)}

	for {
		message, err := reader.ReadString('\n')
		if err != nil {
			fmt.Println("Error reading:", err)
			break
		}

		processMessage(clients[conn], strings.TrimSpace(message))
	}
}

func processMessage(client *Client, message string) {
	if client.role == "admin" && strings.HasPrefix(message, "/") {
		command := strings.SplitN(strings.TrimPrefix(message, "/"), " ", 2)

		if len(command) == 0 {
			return
		}

		switch command[0] {
		case "kick":
			// Implement kick functionality
			fmt.Println("Kicking player:", command[1])
		case "ban":
			// Implement ban functionality
			fmt.Println("Banning player:", command[1])
		case "giveitems":
			// Implement give items functionality
			fmt.Println("Giving items to player:", command[1])
		}
	} else {
		for _, c := range clients {
			if c != client {
				c.conn.Write([]byte(client.username + ": " + message + "\n"))
			}
		}
	}
}